import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';

export const Header = () => {
  const [show, setShow] = useState(false);
  const [activeSection, setActiveSection] = useState('home');
  const [isScrolled, setIsScrolled] = useState(false);

  const { t, i18n } = useTranslation('common');
  const currentLang = i18n.language || 'es';

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 20) {
        setIsScrolled(true);
      } else {
        setIsScrolled(false);
      }
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const sections = ['home', 'whatIdo', 'about', 'work'];
    const observerOptions = {
      root: null,
      rootMargin: '-40% 0px -50% 0px',
      threshold: 0,
    };

    const observerCallback = (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          setActiveSection(entry.target.id);
        }
      });
    };

    const observer = new IntersectionObserver(observerCallback, observerOptions);
    sections.forEach((id) => {
      const element = document.getElementById(id);
      if (element) observer.observe(element);
    });

    return () => observer.disconnect();
  }, []);

  return (
    <header
      className="fixed w-full top-0 left-0 z-50 transition-all duration-300"
      style={{
        fontFamily: "'Poppins', sans-serif",
        background: isScrolled
          ? 'linear-gradient(to right, rgba(255, 255, 255, 0.98), rgba(243, 248, 255, 0.96))'
          : 'transparent',
        backdropFilter: isScrolled ? 'blur(20px)' : 'none',
        WebkitBackdropFilter: isScrolled ? 'blur(20px)' : 'none',
        borderBottom: isScrolled ? '1px solid rgba(229, 231, 235, 0.8)' : '1px solid transparent',
        boxShadow: isScrolled
          ? '0 4px 6px -1px rgba(0, 0, 0, 0.05), 0 2px 4px -1px rgba(0, 0, 0, 0.03)'
          : 'none',
      }}
    >
      <nav
        className={`max-w-6xl mx-auto px-6 flex justify-between items-center transition-all duration-300 ${
          isScrolled ? 'py-3' : 'py-5'
        }`}
      >
        <a
          href="#home"
          className="text-xl font-extrabold text-gray-900 tracking-tight hover:opacity-80 transition-opacity"
        >
          Emanuel Torres<span className="text-blue-600"> C.</span>
        </a>

        <ul className="hidden md:flex items-center space-x-8 font-bold text-sm">
          <li>
            <a
              href="#home"
              className={`relative py-2 transition-colors duration-200 group ${
                activeSection === 'home'
                  ? 'text-blue-600'
                  : isScrolled
                  ? 'text-gray-900 hover:text-blue-600'
                  : 'text-gray-700 hover:text-gray-900'
              }`}
            >
              {t('navigation.home')}
              <span
                className={`absolute bottom-0 left-0 h-0.5 bg-blue-600 transition-all duration-300 ${
                  activeSection === 'home' ? 'w-full' : 'w-0 group-hover:w-full'
                }`}
              ></span>
            </a>
          </li>

          <li>
            <a
              href="#whatIdo"
              className={`relative py-2 transition-colors duration-200 group ${
                activeSection === 'whatIdo'
                  ? 'text-blue-600'
                  : isScrolled
                  ? 'text-gray-900 hover:text-blue-600'
                  : 'text-gray-700 hover:text-gray-900'
              }`}
            >
              {t('navigation.whatIdo')}
              <span
                className={`absolute bottom-0 left-0 h-0.5 bg-blue-600 transition-all duration-300 ${
                  activeSection === 'whatIdo' ? 'w-full' : 'w-0 group-hover:w-full'
                }`}
              ></span>
            </a>
          </li>

          <li>
            <a
              href="#about"
              className={`relative py-2 transition-colors duration-200 group ${
                activeSection === 'about'
                  ? 'text-blue-600'
                  : isScrolled
                  ? 'text-gray-900 hover:text-blue-600'
                  : 'text-gray-700 hover:text-gray-900'
              }`}
            >
              {t('navigation.about')}
              <span
                className={`absolute bottom-0 left-0 h-0.5 bg-blue-600 transition-all duration-300 ${
                  activeSection === 'about' ? 'w-full' : 'w-0 group-hover:w-full'
                }`}
              ></span>
            </a>
          </li>

          <li>
            <a
              href="#work"
              className={`relative py-2 transition-colors duration-200 group ${
                activeSection === 'work'
                  ? 'text-blue-600'
                  : isScrolled
                  ? 'text-gray-900 hover:text-blue-600'
                  : 'text-gray-700 hover:text-gray-900'
              }`}
            >
              {t('navigation.work')}
              <span
                className={`absolute bottom-0 left-0 h-0.5 bg-blue-600 transition-all duration-300 ${
                  activeSection === 'work' ? 'w-full' : 'w-0 group-hover:w-full'
                }`}
              ></span>
            </a>
          </li>

          {/* Selector de idioma adaptado a Tailwind v1 */}
          <li
            className={`flex items-center p-1 rounded-full border transition-all duration-300 ml-4 ${
              isScrolled ? 'bg-gray-200 border-gray-300' : 'bg-white bg-opacity-40 border-gray-200'
            }`}
          >
            <button
              onClick={() => i18n.changeLanguage('es')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all duration-200 ${
                currentLang.startsWith('es')
                  ? 'bg-white text-blue-600 shadow-sm'
                  : 'text-gray-700 hover:text-gray-900'
              }`}
            >
              ES
            </button>
            <button
              onClick={() => i18n.changeLanguage('en')}
              className={`px-3 py-1 text-xs font-bold rounded-full transition-all duration-200 ${
                currentLang.startsWith('en')
                  ? 'bg-white text-blue-600 shadow-sm'
                  : 'text-gray-700 hover:text-gray-900'
              }`}
            >
              EN
            </button>
          </li>
        </ul>

        {/* Botón Hamburguesa Móvil */}
        <button
          className="md:hidden p-2 text-gray-800 hover:text-blue-600 transition-colors rounded-lg"
          onClick={() => setShow(!show)}
        >
          {show ? (
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="2"
                d="M6 18L18 6M6 6l12 12"
              ></path>
            </svg>
          ) : (
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth="2"
                d="M4 6h16M4 12h16M4 18h16"
              ></path>
            </svg>
          )}
        </button>
      </nav>

      {/* Menú Móvil */}
      {show && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white border-b border-gray-200 shadow-xl py-6 px-6 space-y-3 flex flex-col">
          <a
            href="#home"
            className={`font-bold text-base py-2 border-b border-gray-100 transition-colors ${
              activeSection === 'home' ? 'text-blue-600 pl-2' : 'text-gray-800'
            }`}
            onClick={() => setShow(false)}
          >
            {t('navigation.home')}
          </a>
          <a
            href="#whatIdo"
            className={`font-bold text-base py-2 border-b border-gray-100 transition-colors ${
              activeSection === 'whatIdo' ? 'text-blue-600 pl-2' : 'text-gray-800'
            }`}
            onClick={() => setShow(false)}
          >
            {t('navigation.whatIdo')}
          </a>
          <a
            href="#about"
            className={`font-bold text-base py-2 border-b border-gray-100 transition-colors ${
              activeSection === 'about' ? 'text-blue-600 pl-2' : 'text-gray-800'
            }`}
            onClick={() => setShow(false)}
          >
            {t('navigation.about')}
          </a>
          <a
            href="#work"
            className={`font-bold text-base py-2 border-b border-gray-100 transition-colors ${
              activeSection === 'work' ? 'text-blue-600 pl-2' : 'text-gray-800'
            }`}
            onClick={() => setShow(false)}
          >
            {t('navigation.work')}
          </a>
        </div>
      )}
    </header>
  );
};
