import React, { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';

// Tu mapeo estático optimizado
const PROJECT_TAGS = {
  p1: ['Cake PHP', 'Bootstrap', 'Tailwind', 'MySQL', 'Javascript', 'Jquery', 'Ionic'],
  p2: ['Laravel', 'Blade', 'CSS3', 'Jquery'],
  p3: ['Laravel', 'Blade', 'CSS3', 'Jquery'],
  p4: ['Laravel', 'Vue', 'CSS 3'],
  p5: ['Next.js', 'Sass', 'Api rest', 'Mysql'],
  p6: ['Laravel', 'HTML 5', 'Javascript', 'CSS 3'],
  p7: ['Vue', 'Express', 'Node.js', 'Sass', 'Api rest', 'Mysql'],
  p8: ['Beyond JS', 'Polymer', 'Api rest'],
  p9: ['Electron JS'],
  p10: ['Laravel', 'Vue', 'Api rest'],
  p11: ['Wordpress'],
  p12: ['React Native', 'Api Rest', 'Styled Components', 'Typescript'],
  p13: ['Next.js', 'React', 'Sass', 'Api Rest', 'Typescript'],
  p14: ['React', 'Redux', 'Sass', 'Api Rest', 'Typescript'],
  p15: ['React', 'Redux', 'Sass', 'Api Rest', 'Typescript'],
  p16: ['React', 'Zustand', 'Sass', 'Api Rest', 'Typescript'],
  p17: ['React', 'Zustand', 'Sass', 'Api Rest', 'Typescript', 'Next.js'],
};

export const Work = () => {
  const { t } = useTranslation('common');
  const [visibleCount, setVisibleCount] = useState(6);

  const projects = useMemo(() => {
    const projectsData = t('work.projects', { returnObjects: true });
    if (!projectsData) return [];

    return Object.keys(projectsData)
      .map((key) => ({
        id: parseInt(key.replace('p', '')),
        tagKey: key,
        title: t(`work.projects.${key}.title`),
        desc: t(`work.projects.${key}.desc`),
        img: t(`work.projects.${key}.img`),
        url: t(`work.projects.${key}.url`),
      }))
      .sort((projectOne, projectTwo) => projectTwo.id - projectOne.id);
  }, [t]);

  const visibleProjects = useMemo(() => {
    return projects.slice(0, visibleCount);
  }, [projects, visibleCount]);

  const handleShowMore = () => {
    setVisibleCount((prev) => Math.min(prev + 6, projects.length));
  };

  return (
    <section
      className="my-work py-20"
      id="work"
      style={{
        backgroundColor: '#f8fafc',
        height: 'auto',
        display: 'flow-root',
        clear: 'both',
      }}
    >
      <div className="max-w-6xl mx-auto px-6">
        <div className="text-center mb-16">
          <h2 className="text-3xl md:text-5xl font-bold text-gray-900 mb-4 tracking-tight">
            {t('work.title')}
          </h2>
          <p className="text-lg text-gray-500 max-w-2xl mx-auto">{t('work.subtitle')}</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {visibleProjects?.map((project) => (
            <div
              key={project.id}
              className="bg-white border border-gray-100 overflow-hidden shadow-sm hover:shadow-xl transition-all duration-300 flex flex-col justify-between group"
              style={{ borderRadius: '16px' }}
            >
              <div className="overflow-hidden relative bg-gray-100 h-48 w-full">
                <img
                  src={project.img}
                  alt={project.title}
                  className="w-full h-full object-cover transform group-hover:scale-105 transition duration-500"
                />
              </div>

              <div className="p-6 flex-grow flex flex-col justify-between">
                <div>
                  <h3 className="text-xl font-bold text-gray-900 mb-2 tracking-tight group-hover:text-blue-600 transition-colors">
                    {project.title}
                  </h3>
                  <p
                    className="text-gray-600 text-sm leading-relaxed mb-4"
                    style={{
                      display: '-webkit-box',
                      WebkitLineClamp: 12,
                      WebkitBoxOrient: 'vertical',
                      overflow: 'hidden',
                    }}
                  >
                    {project.desc}
                  </p>
                </div>

                <div>
                  <div className="flex flex-wrap gap-2 mb-5">
                    {PROJECT_TAGS[project.tagKey]?.map((tag, index) => (
                      <span
                        key={index}
                        className="bg-gray-100 text-gray-600 capitalize font-medium px-2 py-0.5 text-xs rounded"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>

                  {project.url && (
                    <a
                      href={project.url}
                      target="_blank"
                      className="inline-flex items-center text-sm font-bold text-blue-600 hover:text-blue-800 transition-colors"
                    >
                      {t('work.btn')}
                      <svg
                        className="w-4 h-4 ml-1 transform group-hover:translate-x-1 transition-transform"
                        fill="none"
                        stroke="currentColor"
                        viewBox="0 0 24 24"
                      >
                        <path
                          strokeLinecap="round"
                          strokeLinejoin="round"
                          strokeWidth="2"
                          d="M14 5l7 7m0 0l-7 7m7-7H3"
                        />
                      </svg>
                    </a>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>

        {visibleCount < projects?.length && (
          <div className="text-center mt-12">
            <button
              onClick={handleShowMore}
              className="inline-block bg-white text-gray-900 font-bold px-8 py-3 border border-gray-200 hover:bg-gray-50 hover:border-gray-300 transition-all shadow-sm rounded-full active:scale-95"
            >
              {t('work.loadMore', { count: projects.length - visibleCount })}
            </button>
          </div>
        )}
      </div>
    </section>
  );
};
